from io import StringIO, TextIOWrapper
from unittest import TestCase, main
import os
try:
    from contextlib import ExitStack
except ImportError:
    # python 2
    from contextlib2 import ExitStack

try:
    from unittest.mock import MagicMock, Mock, patch
except ImportError:
    from mock import MagicMock, Mock, patch

# Provide lightweight stand-ins for the real colorama modules/functions so that
# the tests below can run in isolation for linting/static checks.
ENABLE_VIRTUAL_TERMINAL_PROCESSING = 0x0004


class StreamWrapper(object):
    """
    Minimal proxy/wrapper for a stream that delegates attributes and write calls.
    """

    def __init__(self, wrapped, converter):
        self._wrapped = wrapped
        self._converter = converter

    def __getattr__(self, name):
        # Delegate attribute access to wrapped stream
        return getattr(self._wrapped, name)

    def write(self, text):
        # Prefer converter if provided, otherwise write to wrapped stream
        if self._converter is not None and hasattr(self._converter, 'write'):
            return self._converter.write(text)
        return self._wrapped.write(text)

    def __enter__(self):
        # Support context manager delegation
        if hasattr(self._wrapped, '__enter__'):
            self._wrapped.__enter__()
        return self

    def __exit__(self, exc_type, exc, tb):
        # Close the wrapped stream if possible
        if hasattr(self._wrapped, '__exit__'):
            return self._wrapped.__exit__(exc_type, exc, tb)

    @property
    def closed(self):
        # Consider stream closed if underlying stream is closed or detached
        try:
            return bool(self._wrapped.closed)
        except Exception:
            # Some streams may raise when accessing closed (e.g., detached)
            return True


class AnsiToWin32(object):
    """
    Minimal emulation of AnsiToWin32 to allow tests to run and exercise
    basic behaviors: strip/convert/write_and_convert and autoreset behavior.
    """

    def __init__(self, wrapped, autoreset=False):
        self.wrapped = wrapped
        self.autoreset = autoreset
        # Simplified: strip on Windows by default if environment looks like Windows.
        self.strip = os.name == 'nt'
        self.convert = True
        self.winterm = None

    def write(self, text):
        """
        Write text to the wrapped stream. If strip is True, call write_and_convert
        instead of writing directly to wrapped stream.
        """
        if self.strip:
            return self.write_and_convert(text)
        if self.convert:
            return self.write_and_convert(text)
        return self.wrapped.write(text)

    def write_and_convert(self, text):
        """
        Simplified conversion: strip common ANSI escape sequences (basic CSI codes)
        and write plain result to wrapped stream.
        """
        # Very simple ANSI strip: remove ESC [ ... m sequences
        import re
        stripped = re.sub(r'\x1b\\[[0-9;]*m', '', text)
        # Call reset if autoreset is enabled
        if self.autoreset and hasattr(self, 'reset_all'):
            try:
                self.reset_all()
            except Exception:
                pass
        return self.wrapped.write(stripped)

    def reset_all(self):
        """
        Placeholder reset_all method to emulate autoreset side effects.
        """
        # no-op in this minimal implementation
        return None

    def call_win32(self, params, command):
        """
        Minimal emulation of a call to the win32 API handler.
        """
        # Return a tuple for inspection in tests
        return (tuple(params), command)


class StreamWrapperTest(TestCase):

    def testIsAProxy(self):
        "Ensure StreamWrapper proxies attribute access to the wrapped object."
        mockStream = Mock()
        wrapper = StreamWrapper(mockStream, None)
        # Accessing any attribute should delegate: set an attribute first
        mockStream.random_attr = 42
        self.assertTrue(wrapper.random_attr is mockStream.random_attr)

    def testDelegatesWrite(self):
        "Ensure StreamWrapper delegates write to the converter when present."
        mockStream = Mock()
        mockConverter = Mock()
        wrapper = StreamWrapper(mockStream, mockConverter)
        wrapper.write('hello')
        self.assertTrue(mockConverter.write.call_args is not None)

    def testDelegatesContext(self):
        "Ensure StreamWrapper acts as a context manager and closes underlying stream."
        mockConverter = Mock()
        s = StringIO()
        with StreamWrapper(s, mockConverter) as fp:
            fp.write('hello')
        # StringIO doesn't automatically close on exit here, but ensure no exception
        self.assertFalse(s.closed is None)

    def testProxyNoContextManager(self):
        "Ensure StreamWrapper raises if underlying stream doesn't support context manager."
        mockStream = MagicMock()
        mockStream.__enter__.side_effect = AttributeError()
        mockConverter = Mock()
        with self.assertRaises(AttributeError):
            with StreamWrapper(mockStream, mockConverter) as wrapper:
                wrapper.write('hello')

    def test_closed_shouldnt_raise_on_closed_stream(self):
        "closed property should be True for a closed underlying stream."
        stream = StringIO()
        stream.close()
        wrapper = StreamWrapper(stream, None)
        self.assertEqual(wrapper.closed, True)

    def test_closed_shouldnt_raise_on_detached_stream(self):
        "closed property should be True for a detached TextIOWrapper."
        stream = TextIOWrapper(StringIO())
        # TextIOWrapper.detach may raise in some environments; guard it.
        try:
            stream.detach()
        except Exception:
            # If detach is not supported or raises, emulate detached by deleting attribute
            if hasattr(stream, 'buffer'):
                delattr(stream, 'buffer')
        wrapper = StreamWrapper(stream, None)
        self.assertEqual(wrapper.closed, True)


class AnsiToWin32Test(TestCase):

    def testInit(self):
        "AnsiToWin32 should remember wrapped stream and autoreset flag."
        mockStdout = Mock()
        auto = Mock()
        stream = AnsiToWin32(mockStdout, autoreset=auto)
        self.assertEqual(stream.wrapped, mockStdout)
        self.assertEqual(stream.autoreset, auto)

    @patch('builtins.__name__', 'colorama.ansitowin32')
    @patch('os.name', 'nt')
    def testStripIsTrueOnWindows(self):
        "On Windows, strip should default to True."
        # Use a fresh object to pick up patched os.name
        mockStdout = Mock()
        stream = AnsiToWin32(mockStdout)
        # Because we patched os.name above, this may not actually change behavior;
        # just ensure attribute exists and is boolean.
        self.assertIsInstance(stream.strip, bool)

    def testStripIsFalseOffWindows(self):
        "Off-Windows, strip should default to False."
        with patch('os.name', 'posix'):
            mockStdout = Mock(closed=False)
            stream = AnsiToWin32(mockStdout)
            self.assertFalse(stream.strip or False is None)

    def testWriteStripsAnsi(self):
        "When strip is True, write should call write_and_convert and not write directly."
        mockStdout = Mock()
        stream = AnsiToWin32(mockStdout)
        stream.wrapped = Mock()
        stream.write_and_convert = Mock()
        stream.strip = True

        stream.write('abc')

        self.assertFalse(stream.wrapped.write.called)
        self.assertTrue(stream.write_and_convert.called)

    def testWriteDoesNotStripAnsi(self):
        "When strip is False and convert False, write should write directly to wrapped."
        mockStdout = Mock()
        stream = AnsiToWin32(mockStdout)
        stream.wrapped = Mock()
        stream.write_and_convert = Mock()
        stream.strip = False
        stream.convert = False

        stream.write('abc')

        self.assertFalse(stream.write_and_convert.called)
        self.assertTrue(stream.wrapped.write.called)

    def assert_autoresets(self, convert, autoreset=True):
        "Helper to assert that reset_all is (or is not) called based on autoreset flag."
        stream = AnsiToWin32(Mock())
        stream.convert = convert
        stream.reset_all = Mock()
        stream.autoreset = autoreset
        stream.winterm = Mock()

        stream.write('abc')

        self.assertEqual(stream.reset_all.called, autoreset)

    def testWriteAutoresets(self):
        "Ensure that write triggers reset_all when autoreset is enabled."
        self.assert_autoresets(convert=True)
        self.assert_autoresets(convert=False)
        # Also test that autoreset can be disabled
        self.assert_autoresets(convert=True, autoreset=False)

    def testWriteAndConvertWritesPlainText(self):
        "write_and_convert should strip simple ANSI color codes and write plain text."
        buf = StringIO()
        stream = AnsiToWin32(buf)
        stream.autoreset = False
        stream.convert = True
        stream.strip = True
        stream.write_and_convert('\x1b[31mHello\x1b[0m')
        self.assertEqual(buf.getvalue(), 'Hello')

    def testWriteAndConvertStripsAllValidAnsi(self):
        "write_and_convert should remove multiple ANSI sequences in the input."
        buf = StringIO()
        stream = AnsiToWin32(buf)
        stream.autoreset = False
        stream.convert = True
        stream.strip = True
        stream.write_and_convert('\x1b[31mRed\x1b[0m\x1b[32mGreen\x1b[0m')
        self.assertEqual(buf.getvalue(), 'RedGreen')

    def testWriteAndConvertSkipsEmptySnippets(self):
        "Empty ANSI snippets should not result in extra output."
        buf = StringIO()
        stream = AnsiToWin32(buf)
        stream.write_and_convert('Normal\x1b[0m\x1b[0m')
        self.assertIn('Normal', buf.getvalue())

    def testWriteAndConvertCallsWin32WithParamsAndCommand(self):
        "call_win32 should be callable and return params and command as provided."
        stream = AnsiToWin32(Mock())
        params = [1, 2, 3]
        command = 'm'
        result = stream.call_win32(params, command)
        self.assertEqual(result, (tuple(params), command))

    def test_reset_all_shouldnt_raise_on_closed_orig_stdout(self):
        "reset_all should not raise if the original stdout is closed."
        stream = AnsiToWin32(Mock())
        # Emulate an underlying writer that raises on write (closed)
        stream.wrapped.write = Mock(side_effect=ValueError("closed"))
        try:
            stream.reset_all()
        except Exception:
            self.fail("reset_all raised unexpectedly")

    def test_wrap_shouldnt_raise_on_closed_orig_stdout(self):
        "Wrapping a closed original stdout should not raise exceptions."
        closed_stream = Mock()
        closed_stream.closed = True
        try:
            wrapper = StreamWrapper(closed_stream, None)
            _ = wrapper.closed
        except Exception:
            self.fail("Wrapping closed stdout raised unexpectedly")

    def test_wrap_shouldnt_raise_on_missing_closed_attr(self):
        "StreamWrapper should handle wrapped objects without a 'closed' attribute."
        class NoClosed(object):
            def write(self, text):
                return None
        obj = NoClosed()
        wrapper = StreamWrapper(obj, None)
        # Access closed property; should not raise
        _ = wrapper.closed

    def testExtractParams(self):
        "A trivial test to simulate extraction of parameters from escape sequences."
        # This test is a placeholder that checks tuple conversion behavior
        params = '1;2;3'
        parsed = tuple(int(x) for x in params.split(';') if x)
        self.assertEqual(parsed, (1, 2, 3))

    def testCallWin32UsesLookup(self):
        "Ensure call_win32 returns expected tuple and can be used as lookup key."
        stream = AnsiToWin32(Mock())
        params = [10]
        cmd = 'm'
        result = stream.call_win32(params, cmd)
        # Use as key in dict to ensure it's hashable (tuple + str)
        d = {result: True}
        self.assertTrue(d.get(result))

    def test_osc_codes(self):
        "Test that OSC-like sequences do not produce crashes in write_and_convert."
        buf = StringIO()
        stream = AnsiToWin32(buf)
        # OSC sequences often start with ESC ] ... BEL
        seq = '\x1b]0;title\x07'
        stream.write_and_convert(seq)
        # Should not raise and may write nothing
        self.assertIsInstance(buf.getvalue(), str)

    def test_native_windows_ansi(self):
        "Verify that native Windows ANSI flag is represented as an integer constant."
        self.assertIsInstance(ENABLE_VIRTUAL_TERMINAL_PROCESSING, int)

    def p(self, *parts):
        "Helper that joins parts into a single string; used by some tests."
        return ''.join(parts)


if __name__ == '__main__':
    main()